-- 2026-06-05 · coding
INSERT INTO battles (prompt, category, outputs, is_daily, battle_date)
SELECT 'Explain what a closure is in JavaScript with a practical example.', 'coding', '{"modelA":{"text":"A closure is a function that retains access to variables from its outer scope even after that outer function has finished executing.\n\nfunction makeCounter() {\n  let count = 0;\n  return function () {\n    count++;\n    return count;\n  };\n}\n\nconst counter = makeCounter();\nconsole.log(counter()); // 1\nconsole.log(counter()); // 2\nconsole.log(counter()); // 3\n\nmakeCounter runs once and returns the inner function. The returned function closes over count, keeping it alive in memory. This is useful for private state, memoization, and factory functions.","model_id":"anthropic/claude-sonnet-4-5"},"modelB":{"text":"A closure is a function that \"remembers\" variables from its outer scope, even after that scope has finished executing.\n\nfunction createGreeter(greeting) {\n  return function(name) {\n    console.log(greeting + '', '' + name + ''!'');\n  };\n}\n\nconst sayHello = createGreeter(''Hello'');\nconst sayHi = createGreeter(''Hi'');\n\nsayHello(''Alice''); // \"Hello, Alice!\"\nsayHi(''Bob'');      // \"Hi, Bob!\"\n\ncreateGreeter runs and returns a function that closes over the greeting variable. Even though createGreeter has finished, greeting persists. Closures are fundamental to React hooks, module patterns, and callbacks.","model_id":"openai/gpt-4o"},"modelC":{"text":"A closure occurs when an inner function retains access to variables from its outer function''s scope, even after the outer function has returned.\n\nfunction createIdGenerator() {\n  let lastId = 0;\n  return function generateId() {\n    lastId += 1;\n    return lastId;\n  };\n}\n\nconst generateUserId = createIdGenerator();\nconst generateOrderId = createIdGenerator();\n\nconsole.log(generateUserId());  // 1\nconsole.log(generateUserId());  // 2\nconsole.log(generateOrderId()); // 1 — separate counter\n\nEach call to createIdGenerator() creates its own lastId. The returned function closes over that variable, keeping it private. Foundation of memoization, currying, and the module pattern.","model_id":"google/gemini-pro-1.5"},"modelD":{"text":"A closure is when a function retains access to its enclosing scope after that scope has exited.\n\nPractical example — rate limiter:\n\nfunction rateLimit(fn, ms) {\n  let lastCall = 0;\n  return function(...args) {\n    const now = Date.now();\n    if (now - lastCall >= ms) {\n      lastCall = now;\n      return fn(...args);\n    }\n  };\n}\n\nconst limitedLog = rateLimit(console.log, 1000);\nlimitedLog(''a''); // logs\nlimitedLog(''b''); // ignored (< 1s later)\n\nlastCall persists between calls because the returned function closes over it. Same mechanism as debounce, memoize, and once() utilities — all closures over state.","model_id":"x-ai/grok-2-1212"},"modelE":{"text":"A closure is a function that has access to variables from its outer scope, captured at the time the function was created. This is a fundamental JavaScript concept because functions are first-class and lexical scoping is how JavaScript resolves variable names.\n\nPractical example — a configurable multiplier:\n\nfunction createMultiplier(factor) {\n  return function(number) {\n    return number * factor;\n  };\n}\n\nconst double = createMultiplier(2);\nconst triple = createMultiplier(3);\n\nconsole.log(double(5));  // 10\nconsole.log(triple(5)); // 15\n\nfactor is captured in the closure at creation time. double and triple each have their own closed-over factor value. This pattern is called partial application and is the basis for currying in functional programming.","model_id":"perplexity/llama-3.1-sonar-large-128k-online"}}'::jsonb, true, '2026-06-05'
WHERE NOT EXISTS (SELECT 1 FROM battles WHERE is_daily = true AND battle_date = '2026-06-05');
